<template><div class="page"><header class="page-head"><div><h1>Calendrier</h1><p>Sorties films et episodes suivis.</p></div><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></header><div class="toolbar"><input v-model="search" class="search" type="search" placeholder="Filtrer les titres"/><label class="check"><input v-model="tracked" type="checkbox" @change="load"/> Suivis uniquement</label></div><p v-if="error" class="notice error-text">{{ error }}</p><section class="timeline"><article v-for="event in filtered" :key="`${event.instance}:${event.date}:${event.title}:${event.subtitle}`" class="timeline-row"><div class="date-box"><strong>{{ day(event.date) }}</strong><span>{{ month(event.date) }}</span></div><div><strong>{{ event.title }}</strong><span>{{ event.subtitle }} - {{ event.instance }}</span></div><span class="badge" :class="event.tracked?'available':'pending'">{{ event.tracked?'Suivi':'Catalogue' }}</span></article><p v-if="!loading&&filtered.length===0" class="empty">Aucune sortie sur la periode.</p></section></div></template>
<script setup>import { computed,onMounted,ref } from "vue";import { RefreshCw } from "@lucide/vue";import { api } from "@/api";const events=ref([]),search=ref(""),tracked=ref(false),loading=ref(false),error=ref("");const filtered=computed(()=>events.value.filter(e=>!search.value||e.title.toLowerCase().includes(search.value.toLowerCase())));function day(v){return new Date(v).getDate().toString().padStart(2,"0")}function month(v){return new Intl.DateTimeFormat("fr-FR",{month:"short"}).format(new Date(v))}async function load(){loading.value=true;error.value="";try{events.value=await api(`/api/calendar?tracked_only=${tracked.value}`)}catch(e){error.value=e.message}finally{loading.value=false}}onMounted(load);</script>
